const Je={className:"FresnelBlock",emit(e,r,o,m,t){const n=t.cast(t.resolve(e,"worldNormal",o,m),"vec3f").expr,l=t.cast(t.resolve(e,"viewDirection",o,m),"vec3f").expr,c=t.cast(t.resolve(e,"bias",o,m),"f32").expr,s=t.cast(t.resolve(e,"power",o,m),"f32").expr;return("vertex"===o?m.vertex:m.fragment).helpers.set("nme_computeFresnelTerm","fn nme_computeFresnelTerm(viewDirection:vec3<f32>,worldNormal:vec3<f32>,bias:f32,power:f32)->f32{let fresnelTerm=pow(bias+abs(dot(viewDirection,worldNormal)),power);return clamp(fresnelTerm,0.0,1.0);}"),{expr:`nme_computeFresnelTerm(${l},${n},${c},${s})`,type:"f32"};}};export{Je as emitter};